{# Replace the below JSON with the desired state, variables inserted #}
{% set required_params = {
    "state": "enabled",
    "snoozeDurationInDays": CTX.snoozeDays,
    "includeTargets": [
        {
            "id": CTX.includeId.GroupId,
            "targetType": "group",
            "targetedAuthenticationMethod": "microsoftAuthenticator"
        }
    ],
    "excludeTargets": [
        {
            "id": CTX.excludeId.GroupId,
            "targetType": "group"
        }
    ]
} %}
{% set compliance_status = {} %}
{% for key, value in required_params.items() %}
    {# Replace the below CTX value with the data of the standardized item #}
    {% if CTX.RegistrationCampaign[key] == value %}
        {% do compliance_status.update({key: true}) %}
    {% else %}
        {% do compliance_status.update({key: false}) %}
    {% endif %}
{% endfor %}
{{ compliance_status }}

{% set ns = namespace(all_compliant=true) %}
{% for key, value in CTX.Settings.items() %}
    {% if not value == true %}
        {% set ns.all_compliant = false %}
        {% break %}
    {% endif %}
{% endfor %}
{{ ns.all_compliant }}

{% set group_id = None %}
{% for group in CTX.Groups %}
    {% if group.displayName == CTX.GroupName %}
            {{-group.id-}}
    {% endif %}
{% endfor %}
